UPDATE sites SET horario = 'Lunes a sábado, recorridos guiados a las 11:00 a. m., 2:30 p. m. y 5:00 p. m.; domingos a las 3:00 p. m. (festivos cerrado).', tarifa = '$16.000 por persona (aporte cultural).', direccion = 'Carrera 11B #24-44, barrio Obrero.', datos_historicos = 'Fundado hace más de 50 años como un archivo personal que se abrió al mundo. Fundado en 1968 por Carlos Alfredo Molina; el museo de salsa más antiguo del mundo, con 40.000+ fotografías.' WHERE id = 's25';
