UPDATE sites SET horario = 'Jueves a sábado, aprox. 8:00 p. m.–3:00 a. m. (jueves de salsa y bachata; viernes de taxi dancer; sábado de rumba caleña).', tarifa = 'Cover según la noche (desde ~$5.000).', direccion = 'Calle 5 #38-71, sur.', datos_historicos = 'Su nombre viene del famoso tema de Chano Pozo y Dizzy Gillespie, marcando su influencia de Latin Jazz. Fundado en 1985.' WHERE id = 's29';
