UPDATE sites SET horario = 'Zona abierta; fuerte vida gastronómica y nocturna.', tarifa = 'Libre (consumos aparte).', descripcion = 'Uno de los barrios tradicionales de Cali, a orillas del río Cali, contiguo a San Antonio y al Museo La Tertulia; con los años se consolidó como zona bohemia, gastronómica y de anticuarios. En su entorno (Bulevar del Río) se realizan mercados de antigüedades y pulgas los fines de semana.' WHERE id = 's60';
UPDATE sites SET horario = 'Zona abierta; fuerte movimiento nocturno.', tarifa = 'Libre (consumos aparte).', descripcion = 'Barrio residencial del norte de Cali, desarrollado a mediados del siglo XX, que con el tiempo se consolidó como uno de los principales epicentros gastronómicos y de vida nocturna de la ciudad.' WHERE id = 's61';
UPDATE sites SET horario = 'Zona abierta; fuerte vida nocturna.', tarifa = 'Libre (consumos aparte).', descripcion = 'Parque tradicional del barrio San Fernando, cuyo nombre proviene de una escultura de un perro instalada en el lugar; con los años se transformó en una de las principales zonas de gastronomía y rumba de Cali.' WHERE id = 's24';